import{_ as t,c as n,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"7-Stufen-Pipeline-Übersicht: Vollständiger Ablauf von Bootstrap bis Preview | AI App Factory Tutorial","description":"Lernen Sie die vollständige Pipeline von AI App Factory kennen, von der Strukturierung von Produktideen bis zur Erstellung von Deployment-Anleitungen. Verstehen Sie Checkpoints, Berechtigungssteuerung und Fehlerbehandlungsmechanismen.","frontmatter":{"title":"7-Stufen-Pipeline-Übersicht: Vollständiger Ablauf von Bootstrap bis Preview | AI App Factory Tutorial","sidebarTitle":"7-Stufen-Pipeline-Übersicht","subtitle":"7-Stufen-Pipeline-Übersicht","description":"Lernen Sie die vollständige Pipeline von AI App Factory kennen, von der Strukturierung von Produktideen bis zur Erstellung von Deployment-Anleitungen. Verstehen Sie Checkpoints, Berechtigungssteuerung und Fehlerbehandlungsmechanismen.","tags":["Pipeline","Sisyphus","Agent"],"prerequisite":["start-init-project"],"order":40},"headers":[],"relativePath":"de/hyz1992/agent-app-factory/start/pipeline-overview/index.md","filePath":"de/hyz1992/agent-app-factory/start/pipeline-overview/index.md"}'),s={name:"de/hyz1992/agent-app-factory/start/pipeline-overview/index.md"};function a(d,e,o,l,h,u){return i(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="_7-stufen-pipeline-ubersicht" tabindex="-1">7-Stufen-Pipeline-Übersicht <a class="header-anchor" href="#_7-stufen-pipeline-ubersicht" aria-label="Permalink to &quot;7-Stufen-Pipeline-Übersicht&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li>Den vollständigen Ablauf der 7-Stufen-Pipeline und die Verantwortlichkeiten jeder Phase verstehen</li><li>Die Eingaben, Ausgaben und Exit-Kriterien jeder Phase kennen</li><li>Verstehen, wie das Checkpoint-Mechanismus die Qualität gewährleistet</li><li>Verstehen, wie der Sisyphus-Scheduler die Agent-Ausführung koordiniert</li><li>Die Berechtigungsmatrix beherrschen, die verhindert, dass Agenten ihre Befugnisse überschreiten</li><li>Lernen, wie Sie mit &quot;In neuer Sitzung fortsetzen&quot; Tokens sparen können</li></ul><h2 id="grundidee" tabindex="-1">Grundidee <a class="header-anchor" href="#grundidee" aria-label="Permalink to &quot;Grundidee&quot;">​</a></h2><p><strong>Was ist eine Pipeline?</strong></p><p>Die Pipeline von AI App Factory ist eine automatisierte Produktionslinie, die Ihre Produktideen schrittweise in ausführbare Anwendungen verwandelt. Wie eine Fabrikationslinie durchläuft das Rohmaterial (Produktidee) 7 Bearbeitungsschritte (Phasen), um das Endprodukt (vollständige Anwendung) zu erzeugen.</p><p>Jede Bearbeitungsstufe wird von einem spezialisierten Agenten überwacht, der seine Aufgaben erfüllt, ohne die anderen zu stören:</p><table tabindex="0"><thead><tr><th>Phase</th><th>Agent</th><th>Verantwortung</th><th>Ausgabe</th></tr></thead><tbody><tr><td>Bootstrap</td><td>Bootstrap Agent</td><td>Produktidee vertiefend ausarbeiten</td><td><code>input/idea.md</code></td></tr><tr><td>PRD</td><td>PRD Agent</td><td>Produktanforderungsdokument erstellen</td><td><code>artifacts/prd/prd.md</code></td></tr><tr><td>UI</td><td>UI Agent</td><td>Benutzeroberfläche und Prototyp entwerfen</td><td><code>artifacts/ui/ui.schema.yaml</code> + Vorschauseite</td></tr><tr><td>Tech</td><td>Tech Agent</td><td>Technische Architektur entwerfen</td><td><code>artifacts/tech/tech.md</code> + Prisma Schema</td></tr><tr><td>Code</td><td>Code Agent</td><td>Ausführbaren Code generieren</td><td><code>artifacts/backend/</code> + <code>artifacts/client/</code></td></tr><tr><td>Validation</td><td>Validation Agent</td><td>Codequalität verifizieren</td><td><code>artifacts/validation/report.md</code></td></tr><tr><td>Preview</td><td>Preview Agent</td><td>Deployment-Anleitung erstellen</td><td><code>artifacts/preview/README.md</code></td></tr></tbody></table><p><strong>Schlüsselfunktionen</strong></p><ol><li><strong>Checkpoint-Mechanismus</strong>: Nach jeder Phase wird angehalten und auf Ihre Bestätigung gewartet, bevor fortgefahren wird</li><li><strong>Berechtigungsisolierung</strong>: Jeder Agent kann nur autorisierte Verzeichnisse lesen und schreiben, was Verunreinigungen verhindert</li><li><strong>Fehler-Rollback</strong>: Bei Fehlschlagen einer Phase wird automatisch wiederholt; bei fortgesetzten Fehlern wird zum letzten erfolgreichen Checkpoint zurückgekehrt</li><li><strong>Kontextoptimierung</strong>: Unterstützung der Fortsetzung in einer neuen Sitzung, um Tokens zu sparen</li></ol><h2 id="pipeline-ubersicht" tabindex="-1">Pipeline-Übersicht <a class="header-anchor" href="#pipeline-ubersicht" aria-label="Permalink to &quot;Pipeline-Übersicht&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Bootstrap&lt;br/&gt;Produktidee strukturieren] --&gt;|idea.md| B[PRD&lt;br/&gt;Anforderungsdokument erstellen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|prd.md| C[UI&lt;br/&gt;Benutzeroberfläche entwerfen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|ui.schema.yaml| D[Tech&lt;br/&gt;Technische Architektur entwerfen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|tech.md + schema.prisma| E[Code&lt;br/&gt;Ausführbaren Code generieren]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|backend + client| F[Validation&lt;br/&gt;Codequalität verifizieren]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt;|Validierungsbericht| G[Preview&lt;br/&gt;Deployment-Anleitung erstellen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#f0fdf4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#fef3c7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#ede9fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fce7f3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style F fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#d1fae5</span></span></code></pre></div><p><strong>Ausführungsregeln der Pipeline</strong></p><div class="tip custom-block"><p class="custom-block-title">Ausführungsregeln</p><ol><li><strong>Strikte Reihenfolge</strong>: Muss bei Bootstrap beginnen und nacheinander bis Preview ausgeführt werden, ohne Auslassungen oder Parallelisierung</li><li><strong>Einzel-Agent-Aktivierung</strong>: Zu jedem Zeitpunkt kann nur ein Agent arbeiten</li><li><strong>Keine Rückverfolgung</strong>: Bestätigte Artefakte können nicht geändert werden, nur erneute Ausführung der Phase ist möglich</li></ol><p>Hinweis: Dies sind die Ausführungsregeln der Pipeline, nicht die Anzahl der Checkpoint-Optionen. Nach Abschluss jeder Phase bietet Sisyphus 5 Checkpoint-Optionen an (siehe unten &quot;Checkpoint-Mechanismus&quot;-Kapitel).</p></div><h2 id="detailbeschreibung-der-einzelnen-phasen" tabindex="-1">Detailbeschreibung der einzelnen Phasen <a class="header-anchor" href="#detailbeschreibung-der-einzelnen-phasen" aria-label="Permalink to &quot;Detailbeschreibung der einzelnen Phasen&quot;">​</a></h2><h3 id="phase-1-bootstrap-produktidee-strukturieren" tabindex="-1">Phase 1: Bootstrap - Produktidee strukturieren <a class="header-anchor" href="#phase-1-bootstrap-produktidee-strukturieren" aria-label="Permalink to &quot;Phase 1: Bootstrap - Produktidee strukturieren&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Ihre natürlichsprachliche Produktbeschreibung wird in ein strukturiertes Dokument umgewandelt, um Probleme, Nutzer, Wert und Annahmen vertieft zu analysieren.</p><p><strong>Warum ist das wichtig?</strong></p><p>Eine klare Produktdefinition ist die Grundlage der gesamten Pipeline. Wenn dieser Schritt nicht gut gemacht wird, werden alle nachfolgenden Phasen vom Weg abweichen.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td>Natürlichsprachliche Nutzerbeschreibung</td><td>Zum Beispiel: &quot;Ich möchte eine Ausgaben-App machen&quot;</td></tr><tr><td>Ausgabe</td><td><code>input/idea.md</code></td><td>Strukturiertes Dokument zur Produktidee</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] <code>idea.md</code> existiert</li><li>[ ] Beschreibt eine kohärente Produktidee</li><li>[ ] Agent hat die <code>superpowers:brainstorm</code>-Fähigkeit verwendet, um vertieft zu analysieren</li></ul><p><strong>Verpflichtende Fähigkeitsverwendung</strong></p><div class="warning custom-block"><p class="custom-block-title">Verpflichtende Verwendung von superpowers:brainstorm</p><p>In der Bootstrap-Phase muss die <code>superpowers:brainstorm</code>-Fähigkeit verwendet werden, um vertieft zu analysieren. Wenn der Agent die Verwendung dieser Fähigkeit nicht erwähnt, wird das Artefakt abgelehnt und eine erneute Ausführung angefordert.</p></div><h3 id="phase-2-prd-produktanforderungsdokument-erstellen" tabindex="-1">Phase 2: PRD - Produktanforderungsdokument erstellen <a class="header-anchor" href="#phase-2-prd-produktanforderungsdokument-erstellen" aria-label="Permalink to &quot;Phase 2: PRD - Produktanforderungsdokument erstellen&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Die strukturierte Produktidee wird in ein MVP-Produktanforderungsdokument umgewandelt, das den Funktionsumfang, Nichtziele und User Stories klar definiert.</p><p><strong>Warum ist das wichtig?</strong></p><p>Das PRD ist der &quot;Vertrag&quot; zwischen Design und Entwicklung, der klarlegt, &quot;was getan&quot; und &quot;was nicht getan&quot; wird, um Scope Creep zu verhindern.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>input/idea.md</code></td><td>Strukturierte Idee aus der Bootstrap-Phase</td></tr><tr><td>Ausgabe</td><td><code>artifacts/prd/prd.md</code></td><td>MVP-Produktanforderungsdokument</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] PRD enthält Zielbenutzer</li><li>[ ] PRD definiert den MVP-Umfang</li><li>[ ] PRD listet Nichtziele auf</li><li>[ ] PRD enthält keine technischen Implementierungsdetails</li></ul><p><strong>Achtung: PRD enthält keine technischen Details</strong></p><p>Das PRD sollte beschreiben, &quot;was Benutzer brauchen&quot;, nicht &quot;wie es implementiert wird&quot;. Technische Implementierungsdetails werden von den Phasen Tech und Code übernommen.</p><h3 id="phase-3-ui-benutzeroberflache-und-prototyp-entwerfen" tabindex="-1">Phase 3: UI - Benutzeroberfläche und Prototyp entwerfen <a class="header-anchor" href="#phase-3-ui-benutzeroberflache-und-prototyp-entwerfen" aria-label="Permalink to &quot;Phase 3: UI - Benutzeroberfläche und Prototyp entwerfen&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Basierend auf dem PRD wird die UI-Struktur, das Farbschema entworfen und ein im Browser vorschaubarer HTML-Prototyp generiert.</p><p><strong>Warum ist das wichtig?</strong></p><p>Visual Design ermöglicht es Teams und frühen Benutzern, die Produktform intuitiv zu verstehen und Entwicklungsaufwand zu reduzieren.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>artifacts/prd/prd.md</code></td><td>PRD-Dokument</td></tr><tr><td>Ausgabe</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI-Strukturdefinition</td></tr><tr><td>Ausgabe</td><td><code>artifacts/ui/preview.web/index.html</code></td><td>Vorschaubarer HTML-Prototyp</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] <code>ui.schema.yaml</code> existiert</li><li>[ ] Anzahl der Seiten überschreitet nicht 3</li><li>[ ] Vorschauseite kann im Browser geöffnet werden</li><li>[ ] Agent hat die <code>ui-ux-pro-max</code>-Fähigkeit verwendet</li></ul><p><strong>Verpflichtende Fähigkeitsverwendung</strong></p><div class="warning custom-block"><p class="custom-block-title">Verpflichtende Verwendung von ui-ux-pro-max</p><p>In der UI-Phase muss die <code>ui-ux-pro-max</code>-Fähigkeit verwendet werden, um ein professionelles Designsystem zu erstellen. Diese Fähigkeit enthält 67 Stile, 96 Farbpaletten und 100 Branchenregeln.</p></div><h3 id="phase-4-tech-technische-architektur-entwerfen" tabindex="-1">Phase 4: Tech - Technische Architektur entwerfen <a class="header-anchor" href="#phase-4-tech-technische-architektur-entwerfen" aria-label="Permalink to &quot;Phase 4: Tech - Technische Architektur entwerfen&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Es wird eine minimal feasible technische Architektur und Datenmodell entworfen, der Tech-Stack ausgewählt und API-Endpunkte definiert.</p><p><strong>Warum ist das wichtig?</strong></p><p>Die technische Architektur bestimmt die Wartbarkeit, Erweiterbarkeit und Leistung des Codes. Überdesign führt zu Entwicklungsschwierigkeiten, Unterdessign kann Anforderungen nicht unterstützen.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>artifacts/prd/prd.md</code></td><td>PRD-Dokument</td></tr><tr><td>Ausgabe</td><td><code>artifacts/tech/tech.md</code></td><td>Technische Architekturdokumentation</td></tr><tr><td>Ausgabe</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>Prisma-Datenmodell</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] Tech-Stack ist klar deklariert</li><li>[ ] Datenmodell ist mit PRD konsistent</li><li>[ ] Keine vorzeitige Optimierung oder Overdesign wurde durchgeführt</li></ul><p><strong>Standardwahl des Tech-Stacks</strong></p><ul><li>Backend: Node.js + Express + Prisma</li><li>Datenbank: SQLite (Entwicklung) / PostgreSQL (Produktion)</li><li>Frontend: React Native + Expo</li></ul><h3 id="phase-5-code-ausfuhrbaren-code-generieren" tabindex="-1">Phase 5: Code - Ausführbaren Code generieren <a class="header-anchor" href="#phase-5-code-ausfuhrbaren-code-generieren" aria-label="Permalink to &quot;Phase 5: Code - Ausführbaren Code generieren&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Basierend auf dem UI-Schema, dem Tech-Design und dem Prisma-Schema wird vollständiger Frontend- und Backend-Code mit Tests, Konfiguration und Dokumentation generiert.</p><p><strong>Warum ist das wichtig?</strong></p><p>Dies ist der entscheidende Schritt &quot;von der Idee zur Anwendung&quot;, der generierte Code ist ausführbar und produktionsbereit.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI-Strukturdefinition</td></tr><tr><td>Eingabe</td><td><code>artifacts/tech/tech.md</code></td><td>Technische Architekturdokumentation</td></tr><tr><td>Eingabe</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>Datenmodell</td></tr><tr><td>Ausgabe</td><td><code>artifacts/backend/</code></td><td>Backend-Code (Express + Prisma)</td></tr><tr><td>Ausgabe</td><td><code>artifacts/client/</code></td><td>Frontend-Code (React Native)</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] Backend kann gestartet werden ohne schwerwiegende Fehler</li><li>[ ] Client kann gerendert werden und ist zugänglich</li><li>[ ] Keine zusätzliche Authentifizierung oder irrelevante Funktionen wurden eingeführt</li></ul><p><strong>Generierte Inhalte</strong></p><p>Der Code-Agent generiert folgende Inhalte:</p><p><strong>Backend</strong>:</p><ul><li>Express-Server + Routing</li><li>Prisma ORM + Datenmodell</li><li>Unit- und Integrationstests (Vitest)</li><li>API-Dokumentation (Swagger/OpenAPI)</li><li>Seed-Daten (<code>prisma/seed.ts</code>)</li><li>Docker-Konfiguration</li><li>Logging und Monitoring</li></ul><p><strong>Frontend</strong>:</p><ul><li>React Native-Seiten und Komponenten</li><li>React Navigation-Routing</li><li>Unit-Tests (Jest + React Testing Library)</li><li>Umgebungskonfiguration</li></ul><div class="info custom-block"><p class="custom-block-title">Warum keine Authentifizierungsfunktionen generiert?</p><p>AI App Factory konzentriert sich auf MVP und generiert standardmäßig keine komplexen Funktionen wie Authentifizierung und Autorisierung. Diese können in nachfolgenden Iterationen hinzugefügt werden.</p></div><h3 id="phase-6-validation-codequalitat-verifizieren" tabindex="-1">Phase 6: Validation - Codequalität verifizieren <a class="header-anchor" href="#phase-6-validation-codequalitat-verifizieren" aria-label="Permalink to &quot;Phase 6: Validation - Codequalität verifizieren&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Verifiziert, ob der generierte Code Abhängigkeiten korrekt installieren kann, Typ-Check bestanden und Code-Standards erfüllt.</p><p><strong>Warum ist das wichtig?</strong></p><p>Probleme vor der Ausführung des Codes zu finden, vermeidet Fehler nach der Deployment und spart Debugging-Zeit.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>artifacts/backend/</code></td><td>Backend-Code</td></tr><tr><td>Eingabe</td><td><code>artifacts/client/</code></td><td>Frontend-Code</td></tr><tr><td>Ausgabe</td><td><code>artifacts/validation/report.md</code></td><td>Validierungsbericht</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] Validierungsbericht wurde generiert</li><li>[ ] Backend-Abhängigkeiten können korrekt aufgelöst werden</li><li>[ ] Frontend-Abhängigkeiten können korrekt aufgelöst werden</li><li>[ ] TypeScript-Kompilierung ohne schwerwiegende Fehler</li><li>[ ] Prisma-Schema-Verifizierung bestanden</li></ul><p><strong>Validierungsinhalte</strong></p><p>Der Validation-Agent prüft:</p><ol><li><strong>Abhängigkeitsauflösung</strong>: Ist <code>npm install</code> erfolgreich?</li><li><strong>Typ-Check</strong>: Bestanden <code>tsc --noEmit</code>?</li><li><strong>Code-Standards</strong>: Entspricht es <code>policies/code-standards.md</code>?</li><li><strong>Prisma-Schema</strong>: Bestanden <code>prisma validate</code>?</li><li><strong>Test-Durchlaufquote</strong>: Existieren Tests und können sie ausgeführt werden?</li></ol><p><strong>Fehlerbehandlung</strong></p><p>Wenn die Verifizierung fehlschlägt, generiert der Validation-Agent einen detaillierten Fehlerbericht, der auf spezifische Probleme und Lösungsvorschläge hinweist.</p><h3 id="phase-7-preview-deployment-anleitung-erstellen" tabindex="-1">Phase 7: Preview - Deployment-Anleitung erstellen <a class="header-anchor" href="#phase-7-preview-deployment-anleitung-erstellen" aria-label="Permalink to &quot;Phase 7: Preview - Deployment-Anleitung erstellen&quot;">​</a></h3><p><strong>Was wird gemacht?</strong></p><p>Alle Artefakte werden zusammengefasst, um vollständige Ausführungsanweisungen, Deployment-Konfigurationen und Demo-Prozess-Dokumentationen zu erstellen.</p><p><strong>Warum ist das wichtig?</strong></p><p>Dies ist der letzte Schritt der Pipeline, der es Ihnen ermöglicht, die generierte Anwendung schnell auszuführen und bereitzustellen.</p><p><strong>Eingaben und Ausgaben</strong></p><table tabindex="0"><thead><tr><th>Typ</th><th>Pfad</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Eingabe</td><td><code>artifacts/backend/</code></td><td>Backend-Code</td></tr><tr><td>Eingabe</td><td><code>artifacts/client/</code></td><td>Frontend-Code</td></tr><tr><td>Ausgabe</td><td><code>artifacts/preview/README.md</code></td><td>Vollständige Ausführungsanweisungen</td></tr><tr><td>Ausgabe</td><td><code>artifacts/preview/GETTING_STARTED.md</code></td><td>Schnellstart-Anleitung</td></tr></tbody></table><p><strong>Exit-Kriterien</strong></p><ul><li>[ ] README enthält Installationsanweisungen</li><li>[ ] README enthält Ausführungsbefehle</li><li>[ ] README listet Zugriffsadressen und Demo-Prozesse auf</li></ul><p><strong>Generierte Inhalte</strong></p><p>Der Preview-Agent generiert:</p><ul><li>Lokale Ausführungsanweisungen (Web, iOS, Android)</li><li>Docker-Deployment-Konfiguration (<code>docker-compose.yml</code>)</li><li>CI/CD-Konfigurationsreferenz (GitHub Actions)</li><li>Git Hooks-Konfigurationsreferenz (Husky)</li><li>Datenbank-Migrationsanleitung (SQLite → PostgreSQL)</li></ul><h2 id="checkpoint-mechanismus" tabindex="-1">Checkpoint-Mechanismus <a class="header-anchor" href="#checkpoint-mechanismus" aria-label="Permalink to &quot;Checkpoint-Mechanismus&quot;">​</a></h2><p><strong>Was ist ein Checkpoint?</strong></p><p>Nach Abschluss jeder Phase wird die Pipeline angehalten, um Ihnen eine Liste der generierten Artefakte zu zeigen. Sie können bestätigen, ob sie Ihren Erwartungen entsprechen. Wenn nicht, können Sie &quot;Wiederholen&quot; oder &quot;Nach Änderung erneut ausführen&quot; wählen.</p><p><strong>Warum werden Checkpoints benötigt?</strong></p><ul><li><strong>Verhindert Fehlerakkumulation</strong>: Frühe Probleme, die nicht in der aktuellen Phase gelöst werden, werden in nachfolgenden Phasen verstärkt</li><li><strong>Gewährleistet Qualität</strong>: Jede Phase stellt sicher, dass die Ausgabe den Erwartungen entspricht, um Generierung unbrauchbaren Codes zu vermeiden</li><li><strong>Flexible Steuerung</strong>: Sie können an einem beliebigen Checkpoint anhalten, wiederholen oder Eingaben ändern</li></ul><p><strong>Checkpoint-Optionen</strong></p><p>Nach Abschluss jeder Phase zeigt der Sisyphus-Scheduler folgende Optionen an:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Option │ Beschreibung                                          │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ Nächste Phase fortsetzen (gleiche Sitzung)              │</span></span>
<span class="line"><span>│      │ Ich werde mit der [Nächste Phasenname]-Phase fortfahren│</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ In neuer Sitzung fortsetzen ⭐ Empfohlene Option, Tokens sparen │</span></span>
<span class="line"><span>│      │ Führen Sie in einem neuen Befehlsfenster aus: factory continue        │</span></span>
<span class="line"><span>│      │ (Startet automatisch ein neues Claude Code-Fenster und setzt die Pipeline fort)        │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ Phase erneut ausführen                                 │</span></span>
<span class="line"><span>│      │ [Aktuelle Phasenname]-Phase erneut ausführen           │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ Nach Änderung der Artefakte erneut ausführen           │</span></span>
<span class="line"><span>│      │ Ändern Sie [eine Eingabedatei] und führen Sie erneut aus│</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ Pipeline anhalten                                      │</span></span>
<span class="line"><span>│      │ Speichern Sie den aktuellen Fortschritt und setzen Sie später fort│</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Empfohlene Vorgehensweise</strong></p><div class="tip custom-block"><p class="custom-block-title">Wählen Sie &quot;In neuer Sitzung fortsetzen&quot;, um Tokens zu sparen</p><p>Nach Abschluss jeder Phase wird empfohlen, &quot;In neuer Sitzung fortsetzen&quot; (Option 2) zu wählen:</p><ol><li>Führen Sie <code>factory continue</code> in einem neuen Befehlsfenster aus</li><li>Der Befehl startet automatisch ein neues Claude Code-Fenster</li><li>Jede Phase genießt einen sauberen Kontext und vermeidet Token-Akkumulation</li></ol></div><h2 id="berechtigungsmatrix" tabindex="-1">Berechtigungsmatrix <a class="header-anchor" href="#berechtigungsmatrix" aria-label="Permalink to &quot;Berechtigungsmatrix&quot;">​</a></h2><p><strong>Warum wird Berechtigungsisolierung benötigt?</strong></p><p>Wenn Agenten beliebige Verzeichnisse lesen und schreiben könnten, könnte dies führen zu:</p><ul><li>Bootstrap Agent ändert versehentlich das bereits abgeschlossene PRD</li><li>Code Agent löscht versehentlich das UI-Design</li><li>Validation Agent ändert versehentlich Backend-Code</li></ul><p><strong>Kompetenzgrenzen-Matrix</strong></p><p>Der Sisyphus-Scheduler prüft vor und nach der Ausführung jeder Phase die Berechtigungen des Agenten:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Kann lesen</th><th>Kann schreiben</th></tr></thead><tbody><tr><td>bootstrap</td><td>Keine</td><td><code>input/</code></td></tr><tr><td>prd</td><td><code>input/</code></td><td><code>artifacts/prd/</code></td></tr><tr><td>ui</td><td><code>artifacts/prd/</code></td><td><code>artifacts/ui/</code></td></tr><tr><td>tech</td><td><code>artifacts/prd/</code></td><td><code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td></tr><tr><td>code</td><td><code>artifacts/ui/</code>, <code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td></tr><tr><td>validation</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/validation/</code></td></tr><tr><td>preview</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/preview/</code></td></tr></tbody></table><p><strong>Behandlung von Berechtigungsüberschreitungen</strong></p><p>Wenn ein Agent in ein nicht autorisiertes Verzeichnis schreibt, verschiebt der Sisyphus-Scheduler die Datei nach <code>artifacts/_untrusted/&lt;stage-id&gt;/</code>, hält die Pipeline an und berichtet.</p><div class="warning custom-block"><p class="custom-block-title">Beispiel für Berechtigungsüberschreitung</p><p>Angenommen, der PRD-Agent schreibt in <code>artifacts/ui/ui.schema.yaml</code> (dies ist nicht sein Berechtigungsbereich), dann:</p><ol><li>Verschiebt der Scheduler die Datei nach <code>artifacts/_untrusted/prd/ui.schema.yaml</code></li><li>Hält die Pipeline an</li><li>Berichtet: Berechtigungsüberschreitung erkannt, bitte manuell bearbeiten</li></ol></div><h2 id="fehlerbehandlung" tabindex="-1">Fehlerbehandlung <a class="header-anchor" href="#fehlerbehandlung" aria-label="Permalink to &quot;Fehlerbehandlung&quot;">​</a></h2><p><strong>Was zählt als Fehlschlag?</strong></p><ul><li>Ausgabedateien fehlen</li><li>Artefakte erfüllen nicht <code>exit_criteria</code></li><li>Agent hat in nicht autorisierte Verzeichnisse geschrieben</li><li>Skriptfehler oder Eingabedateien können nicht gelesen werden</li></ul><p><strong>Standard-Behandlungsstrategie</strong></p><ol><li><strong>Automatische Wiederholung</strong>: Jede Phase erlaubt eine automatische Wiederholung</li><li><strong>Fehlschlags-Archivierung</strong>: Fehlgeschlagene Artefakte werden nach <code>artifacts/_failed/&lt;stage-id&gt;/</code> verschoben</li><li><strong>Pipeline anhalten</strong>: Nach zwei aufeinanderfolgenden Fehlschlägen wird auf manuelle Eingriffe gewartet</li><li><strong>Rollback-Mechanismus</strong>: Zurück zum letzten erfolgreichen Checkpoint und erneute Ausführung</li></ol><div class="tip custom-block"><p class="custom-block-title">Behandlung nach manueller Intervention</p><p>Wenn zwei aufeinanderfolgende Fehlschläge auftreten, können Sie:</p><ol><li>Eingabedateien ändern (z. B. <code>input/idea.md</code>)</li><li>Agent-Prompt anpassen</li><li>Berechtigungsprobleme beheben</li><li><code>factory run [stage]</code> ausführen, um von dieser Phase neu zu beginnen</li></ol></div><h2 id="statusmanagement" tabindex="-1">Statusmanagement <a class="header-anchor" href="#statusmanagement" aria-label="Permalink to &quot;Statusmanagement&quot;">​</a></h2><p><strong>Statusdatei</strong></p><p>Der gesamte Status der Pipeline wird in <code>.factory/state.json</code> gespeichert, einschließlich:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;started_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:30:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Zustandsautomat</strong></p><table tabindex="0"><thead><tr><th>Status</th><th>Bedeutung</th><th>Auslöser</th></tr></thead><tbody><tr><td>idle</td><td>Nicht gestartet</td><td>Warte auf <code>factory run</code></td></tr><tr><td>running</td><td>Wird ausgeführt</td><td>Beginnt Ausführung eines Stages</td></tr><tr><td>waiting_for_confirmation</td><td>Wartet auf Bestätigung</td><td>Phase abgeschlossen</td></tr><tr><td>paused</td><td>Angehalten</td><td>Benutzer wählt anhalten</td></tr><tr><td>failed</td><td>Fehler, Eingriffe erforderlich</td><td>Aufeinanderfolgende Fehlschläge oder Berechtigungsüberschreitungen</td></tr></tbody></table><p>Nur der Sisyphus-Scheduler hat die Berechtigung, den Status zu aktualisieren.</p><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="haufiger-fehler-1-bootstrap-phase-hat-brainstorm-fahigkeit-nicht-verwendet" tabindex="-1">Häufiger Fehler 1: Bootstrap-Phase hat brainstorm-Fähigkeit nicht verwendet <a class="header-anchor" href="#haufiger-fehler-1-bootstrap-phase-hat-brainstorm-fahigkeit-nicht-verwendet" aria-label="Permalink to &quot;Häufiger Fehler 1: Bootstrap-Phase hat brainstorm-Fähigkeit nicht verwendet&quot;">​</a></h3><p><strong>Phänomen</strong>: Sisyphus lehnt <code>input/idea.md</code> ab, mit der Meldung &quot;Es wurde erkannt, dass die superpowers:brainstorm-Fähigkeit nicht verwendet wurde&quot;.</p><p><strong>Ursache</strong>: Der Bootstrap-Agent hat die <code>superpowers:brainstorm</code>-Fähigkeit nicht verwendet, um die Produktidee vertieft zu analysieren.</p><p><strong>Lösung</strong>: Wählen Sie bei der Bestätigung der Artefakte &quot;Phase erneut ausführen&quot; und fordern Sie den Agenten ausdrücklich auf, die <code>superpowers:brainstorm</code>-Fähigkeit zu verwenden.</p><h3 id="haufiger-fehler-2-ui-phase-design-ist-durchschnittlich" tabindex="-1">Häufiger Fehler 2: UI-Phase Design ist durchschnittlich <a class="header-anchor" href="#haufiger-fehler-2-ui-phase-design-ist-durchschnittlich" aria-label="Permalink to &quot;Häufiger Fehler 2: UI-Phase Design ist durchschnittlich&quot;">​</a></h3><p><strong>Phänomen</strong>: Generierte UI-Designs sehen alle gleich aus, lila Gradienten, Inter-Schriftart.</p><p><strong>Ursache</strong>: Der UI-Agent hat die <code>ui-ux-pro-max</code>-Fähigkeit nicht verwendet.</p><p><strong>Lösung</strong>: Wählen Sie bei der Bestätigung der Artefakte &quot;Phase erneut ausführen&quot; und fordern Sie den Agenten ausdrücklich auf, die <code>ui-ux-pro-max</code>-Fähigkeit zu verwenden, und geben Sie eine klare ästhetische Richtung an (z. B. &quot;Cyberpunk&quot;, &quot;Minimalismus&quot;).</p><h3 id="haufiger-fehler-3-code-phase-hat-authentifizierungsfunktionen-generiert" tabindex="-1">Häufiger Fehler 3: Code-Phase hat Authentifizierungsfunktionen generiert <a class="header-anchor" href="#haufiger-fehler-3-code-phase-hat-authentifizierungsfunktionen-generiert" aria-label="Permalink to &quot;Häufiger Fehler 3: Code-Phase hat Authentifizierungsfunktionen generiert&quot;">​</a></h3><p><strong>Phänomen</strong>: Der generierte Backend-Code enthält komplexe Funktionen wie JWT-Authentifizierung und Benutzeranmeldung.</p><p><strong>Ursache</strong>: Der Code-Agent hat den MVP-Umfang überschritten.</p><p><strong>Lösung</strong>: Ändern Sie das PRD und listen Sie explizit &quot;Nichtziele&quot; auf (z. B. &quot;Keine Benutzeranmeldung&quot;, &quot;Keine Multi-User-Kollaboration&quot;), dann führen Sie die Code-Phase erneut aus.</p><h3 id="haufiger-fehler-4-token-verbrauch-zu-hoch" tabindex="-1">Häufiger Fehler 4: Token-Verbrauch zu hoch <a class="header-anchor" href="#haufiger-fehler-4-token-verbrauch-zu-hoch" aria-label="Permalink to &quot;Häufiger Fehler 4: Token-Verbrauch zu hoch&quot;">​</a></h3><p><strong>Phänomen</strong>: In späteren Phasen der Pipeline steigt der Token-Verbrauch drastisch an, die AI-Assistent-Reaktion wird langsamer.</p><p><strong>Ursache</strong>: Mehrere Phasen werden in derselben Sitzung ausgeführt, der Kontext akkumuliert ständig.</p><p><strong>Lösung</strong>: <strong>Wählen Sie immer &quot;In neuer Sitzung fortsetzen&quot;</strong> (Option 2), damit jede Phase einen sauberen Kontext hat.</p><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Die Pipeline enthält 7 Phasen: Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Nach jeder Phase wird zur Bestätigung angehalten, um sicherzustellen, dass die Ausgabe den Erwartungen entspricht</li><li>Der Sisyphus-Scheduler koordiniert die Agent-Ausführung, verwaltet Status und Berechtigungen</li><li>Die Kompetenzgrenzen-Matrix verhindert, dass Agenten ihre Befugnisse überschreiten, und gewährleistet die Trennung der Verantwortlichkeiten</li><li>Die Wahl von &quot;In neuer Sitzung fortsetzen&quot; kann Tokens erheblich sparen</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../platforms/claude-code/">Claude Code-Integrationsleitfaden</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie Claude Code-Berechtigungen konfigurieren</li><li>Wie Sie die Pipeline ausführen</li><li>Best Practices für Claude Code</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Pipeline-Definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-111</td></tr><tr><td>Scheduler-Kern</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-302</td></tr><tr><td>Projekt README</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>1-253</td></tr></tbody></table><p><strong>Schlüsselkonstanten</strong>:</p><ul><li>Pipeline-Modus: <code>checkpoint</code> (Checkpoint-Modus, Anhalten zur Bestätigung nach jeder Phase)</li></ul><p><strong>Schlüssel-Agent-Definitionen</strong>:</p><ul><li><strong>Bootstrap Agent</strong>: Verwendet <code>superpowers:brainstorm</code>-Fähigkeit, generiert <code>input/idea.md</code></li><li><strong>PRD Agent</strong>: Liest <code>input/idea.md</code>, generiert <code>artifacts/prd/prd.md</code></li><li><strong>UI Agent</strong>: Verwendet <code>ui-ux-pro-max</code>-Fähigkeit, generiert <code>artifacts/ui/ui.schema.yaml</code> und Vorschauseite</li><li><strong>Tech Agent</strong>: Generiert <code>artifacts/tech/tech.md</code> und <code>artifacts/backend/prisma/schema.prisma</code></li><li><strong>Code Agent</strong>: Generiert basierend auf UI, Tech, Schema <code>artifacts/backend/</code> und <code>artifacts/client/</code></li><li><strong>Validation Agent</strong>: Verifiziert Codequalität, generiert <code>artifacts/validation/report.md</code></li><li><strong>Preview Agent</strong>: Generiert <code>artifacts/preview/README.md</code></li></ul></details>`,158)])])}const p=t(s,[["render",a]]);export{g as __pageData,p as default};
